/* ============================================================
   topbar.css — แถบบนของทุกหน้าหลัง login
   มี: ปุ่มเปิดเมนู (มือถือ), หัวข้อหน้า, ค้นหา, แจ้งเตือน, โปรไฟล์ผู้ใช้
   ============================================================ */

.topbar {
  position: sticky;
  top: 0;
  height: var(--topbar-height);
  background: var(--color-bg);
  border-bottom: 1px solid var(--color-border);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 var(--space-5);
  gap: var(--space-4);
  z-index: 20;
}

.topbar-left {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  min-width: 0;
}

.topbar-menu-btn {
  display: none;
  width: 38px;
  height: 38px;
  align-items: center;
  justify-content: center;
  border-radius: var(--radius-md);
  color: var(--color-text-muted);
  font-size: 20px;
}
.topbar-menu-btn:hover { background: var(--color-bg-canvas); }

.topbar-page-title {
  font-size: var(--fs-h2);
  font-weight: 600;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.topbar-breadcrumb {
  font-size: var(--fs-tiny);
  color: var(--color-text-muted);
}

.topbar-right {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  flex-shrink: 0;
}

.topbar-icon-btn {
  position: relative;
  width: 38px;
  height: 38px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  color: var(--color-text-muted);
  font-size: 18px;
}
.topbar-icon-btn:hover { background: var(--color-bg-canvas); color: var(--color-primary); }

.topbar-icon-btn .badge-dot {
  position: absolute;
  top: 6px;
  right: 7px;
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--color-primary);
  border: 2px solid var(--color-bg);
}

.topbar-user {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  padding: 6px 10px 6px 6px;
  border-radius: var(--radius-full);
  border: 1px solid var(--color-border);
}
.topbar-user:hover { background: var(--color-bg-canvas); }

.topbar-user-avatar {
  width: 30px;
  height: 30px;
  border-radius: 50%;
  background: var(--color-primary-light);
  color: var(--color-primary);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: var(--fs-small);
  font-weight: 600;
  flex-shrink: 0;
}

.topbar-user-info {
  display: flex;
  flex-direction: column;
  line-height: 1.25;
}

.topbar-user-name {
  font-size: var(--fs-small);
  font-weight: 500;
  white-space: nowrap;
}

.topbar-user-role {
  font-size: var(--fs-tiny);
  color: var(--color-text-muted);
}

@media (max-width: 1024px) {
  .topbar-menu-btn { display: flex; }
}

@media (max-width: 640px) {
  .topbar { padding: 0 var(--space-3); }
  .topbar-user-info { display: none; }
  .topbar-page-title { font-size: var(--fs-h3); }
}
